/// <summary>
/// This method accepts parameters and calculates the total amount after matching MainAccountId, ReportId, ReportPerticularId and SubledgerVoucher
/// </summary>
/// <param name = "mainAccountListStr"></param>
/// <param name = "contract"></param>
/// <param name = "invoiceQty"></param>
/// <param name = "contractQty"></param>
/// <param name = "conLedgerVoucher"></param>
/// <returns>totalAmount</returns>
private Amount calculateTotalForMainAccounts(String255 mainAccountListStr, str contract, Qty invoiceQty, Qty contractQty, container conLedgerVoucher)
{
    Amount totalAmount = 0;
    Amount totalCost = 0;
    ETGGMRReportView reportView;
    GeneralJournalAccountEntry gjae;
    ETGPowerBIReportGLMappingTable glMappingTable;

    if(contractQty == 0)
    {
        return 0;
    }

    for (int counter = 1; counter <= conLen(conLedgerVoucher); counter++)
    {
        str voucher = conPeek(conLedgerVoucher, counter);

        select sum(AccountingCurrencyAmount) from reportView
        exists join glMappingTable
        where glMappingTable.MainAccountId == reportView.MainAccountId
            && glMappingTable.ReportId == reportName
            && glMappingTable.ReportPerticularId == mainAccountListStr
            && reportView.SubledgerVoucher == voucher;

        totalAmount = reportView.AccountingCurrencyAmount;
    }

    totalAmount = totalAmount * invoiceQty/ contractQty;

    return totalAmount;
    //Amount totalAmount = 0;
    //Amount totalCost = 0;
    //ETGGMRReportView reportView;
    //GeneralJournalAccountEntry gjae;
    //ETGPowerBIReportGLMappingTable glMappingTable;

    //for (int counter = 1; counter <= conLen(conLedgerVoucher); counter++)
    //{
    //    str voucher = conPeek(conLedgerVoucher, counter);

    //    while select AccountingCurrencyAmount from reportView
    //    exists join glMappingTable
    //    where glMappingTable.MainAccountId == reportView.MainAccountId
    //        && glMappingTable.ReportId == reportName
    //        && glMappingTable.ReportPerticularId == mainAccountListStr
    //        && reportView.SubledgerVoucher == voucher
    //    {
    //        totalAmount += reportView.AccountingCurrencyAmount;
    //    }

    //}
    //if(contractQty == 0)
    //{
    //    return 0;
    //}
    //else
    //{
    //    totalAmount = totalAmount * invoiceQty/ contractQty;
    //}
    //return totalAmount;
}

public void getMainAccountDetails(CustInvoiceJour custInvJour, CustInvoiceTrans custInvoiceTrans)
{
    String50 contract;
    Qty contractQty;
    container conLedgerVoucher;
    CustInvoiceJour custInvJourSum;
    CustInvoiceJour custInvoiceJourLoc;
    int counter = 1;
    CustInvoiceTrans custInvTrans;

    contract    = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(custInvJour.DefaultDimension, acfParam.Contract);

    select sum(Qty) from custInvTrans
        exists join custInvJourSum
        where custInvJourSum.InvoiceId == custInvTrans.InvoiceId
        && custInvJourSum.DataAreaId == custInvTrans.DataAreaId
        && custInvJourSum.ETGContractNum == contract
        && custInvJourSum.DataAreaId == curExt()
        && custInvJourSum.InvoiceDate >= fromDate && custInvJourSum.InvoiceDate <= toDate;

    contractQty = custInvTrans.Qty;

    while select LedgerVoucher, InvoiceId, DataAreaId from custInvoiceJourLoc
        where custInvoiceJourLoc.ETGContractNum == contract
         && custInvoiceJourLoc.InvoiceDate >= fromDate && custInvoiceJourLoc.InvoiceDate <= toDate
    {
        conLedgerVoucher = conIns(conLedgerVoucher, counter, custInvoiceJourLoc.LedgerVoucher);
        counter++;
    }

    etggmctableTemp.ContractQty                 = contractQty;
    etggmctableTemp.InvoiceQty                  = custInvoiceTrans.Qty;
    etggmctableTemp.SalesDiscount               = this.calculateTotalForMainAccounts(strSalesDiscount,              contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher) ;
    etggmctableTemp.PurchDiscount               = this.calculateTotalForMainAccounts(strPurchaseDiscount,           contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher) ;
    etggmctableTemp.SDCost                      = this.calculateTotalForMainAccounts(strSDCost,                     contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher) ;
    etggmctableTemp.DirectCost                  = this.calculateTotalForMainAccounts(strDirectCost,                 contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher) ;
    etggmctableTemp.MmFV                        = this.calculateTotalForMainAccounts(strMmFV,                       contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher) ;
    etggmctableTemp.MmSIT                       = this.calculateTotalForMainAccounts(strMmSIT,                      contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher) ;
    etggmctableTemp.InsuranceClaimRecId         = this.calculateTotalForMainAccounts(strInsuranceClaimRecId,        contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher);
    etggmctableTemp.RealisedExchangeAdjustment  = this.calculateTotalForMainAccounts(strRealisedExchangeAdjustment, contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher);
    etggmctableTemp.Depreciation                = this.calculateTotalForMainAccounts(strDepreciation,               contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher);
    etggmctableTemp.AdminCostAndBankCharges     = this.calculateTotalForMainAccounts(strAdminCostAndBankCharges,    contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher);
    etggmctableTemp.CostStaff                   = this.calculateTotalForMainAccounts(strStaffCost,                  contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher);
    etggmctableTemp.UnrealizedForex             = this.calculateTotalForMainAccounts(strUnrealizedForex,            contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher);
    etggmctableTemp.OtherFinanceCostsLC         = this.calculateTotalForMainAccounts(strOtherFinCosts,              contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher);
    etggmctableTemp.InterestIncome              = this.calculateTotalForMainAccounts(strInterestIncome,             contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher);
    etggmctableTemp.InterestExpense             = this.calculateTotalForMainAccounts(strInterestExpense,            contract, custInvoiceTrans.Qty, contractQty, conLedgerVoucher);

    etggmctableTemp.TotalCost                   = (etggmctableTemp.PurchaseCost + etggmctableTemp.SalesDiscount+etggmctableTemp.PurchDiscount+etggmctableTemp.SDCost+ etggmctableTemp.DirectCost+etggmctableTemp.MmFV+ etggmctableTemp.MmSIT + etggmctableTemp.InsuranceClaimRecId);
    etggmctableTemp.GC                          = (etggmctableTemp.LineAmount -  etggmctableTemp.TotalCost - etggmctableTemp.RealisedExchangeAdjustment);
    etggmctableTemp.OtherCost                   = (etggmctableTemp.Depreciation + etggmctableTemp.AdminCostAndBankCharges + etggmctableTemp.CostStaff + etggmctableTemp.UnrealizedForex );
    etggmctableTemp.EBITDA                      = etggmctableTemp.GC - etggmctableTemp.OtherCost;
    etggmctableTemp.NetEBITDA                   = etggmctableTemp.EBITDA - (etggmctableTemp.OtherFinanceCostsLC + etggmctableTemp.InterestIncome + etggmctableTemp.InterestExpense);
}

private void initializeMainAccount()
{
    ETGGMRReportMainAccountName gmrReportMainAccountName;

    select firstonly gmrReportMainAccountName where gmrReportMainAccountName.DataAreaId == curExt();

    strSalesDiscount              = gmrReportMainAccountName.SALESDISCOUNT;
    strPurchaseDiscount           = gmrReportMainAccountName.PURCHASEDISCOUNT;
    strSDCost                     = gmrReportMainAccountName.SNDCOST;
    strDirectCost                 = gmrReportMainAccountName.DIRECTCOST;
    strMmFV                       = gmrReportMainAccountName.M2MFV;
    strMmSIT                      = gmrReportMainAccountName.M2MSIT;
    strInsuranceClaimRecId        = gmrReportMainAccountName.OTHERINCOMEINSURANCESLAINCOME;
    strTotalCost                  = gmrReportMainAccountName.TOTALCOST;
    strRealisedExchangeAdjustment = gmrReportMainAccountName.REALISEDEXCHANGEADJUSTMENT;
    strGC                         = gmrReportMainAccountName.GC;
    strDepreciation               = gmrReportMainAccountName.DEPRECIATION;
    strAdminCostAndBankCharges    = gmrReportMainAccountName.ADMINCOSTANDBANKCHARGES;
    strStaffCost                  = gmrReportMainAccountName.STAFFCOST;
    strUnrealizedForex            = gmrReportMainAccountName.UNREALIZEDFOREX;
    strOtherCost                  = gmrReportMainAccountName.OTHERCOST;
    strEBITDA                     = gmrReportMainAccountName.EBITDA;
    strOtherFinCosts              = gmrReportMainAccountName.OTHERFINCOSTS;
    strInterestIncome             = gmrReportMainAccountName.INTERESTINCOME;
    strInterestExpense            = gmrReportMainAccountName.INTERESTEXPENSE;
    strNetEBITDA                  = gmrReportMainAccountName.NETEBITDA;
}

/// <summary>
/// This method returns a container having Main accounts from powerBIReportGLMappingTable corresponding to the perticularId passed
/// </summary>
/// <param name = "perticularId"></param>
/// <returns></returns>
public str getMainAccountStrByPerticularId(str perticularId)
{
    ETGPowerBIReportGLMappingTable powerBIReportGLMappingTable;
    container mainAccountCon;
    int counter = 1;

    while select MainAccountId from powerBIReportGLMappingTable
    where powerBIReportGLMappingTable.ReportId == 'GMR'
        && powerBIReportGLMappingTable.ReportPerticularId == perticularId
    {
        mainAccountCon = conIns(mainAccountCon, counter, powerBIReportGLMappingTable.MainAccountId);
        counter++;
    }

    return con2Str(mainAccountCon, ';');
}

public void processReport()
{
    CustInvoiceJour custInvoiceJour;
    CustInvoiceTrans custInvoiceTrans;
    CustTable custTable;
    SalesLine salesLine;
    SalesTable salesTable;
    ETG_SalesTableTrade salesTableTrade;
    AgreementHeader agreementHeader;
    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    SalesAgreementHeader salesAgreementHeader;

    Query query;
    QueryRun                            queryRun;
    QueryBuildDataSource                qbdsCustInvoiceJour, qbdsCustInvoiceTrans,qbdsSalesTable;
    QueryBuildDataSource                qbdsSalesAgreementHeader;
    QueryBuildRange                     qbrToDate;
    ETGGMCTableTemp                     gmrReportTemp,gmrReportTemploc;
    ETGGMCTableTempNonInvoice           gmrReportTempNonInvoice;

    RecordInsertList                     recordgmrReportTemp;
    recordgmrReportTemp = new RecordInsertList(tableNum(ETGGMCTableTemp));

    ETGACFParameters acfParameters = ETGACFParameters::find();

    ETGGMCReportContract contract = this.parmDataContract() as ETGGMCReportContract;

    fromDate = contract.parmFromDate();
    toDate   = contract.parmPerDate();

    acfParam = ETGACFParameters::find();

    delete_from gmrReportTemp;
    delete_from gmrReportTempNonInvoice;

    query           =   new query();
    qbdsCustInvoiceJour  =   query.addDataSource(tableNum(CustInvoiceJour));
    qbdsCustInvoiceTrans   =   qbdsCustInvoiceJour.addDataSource(tableNum(CustInvoiceTrans));
    qbdsCustInvoiceTrans.joinMode(JoinMode::InnerJoin);
    qbdsCustInvoiceTrans.relations(true);

    if(fromDate && toDate)
    {
        if(toDate < fromDate)
        {
            throw Error(strFmt("To date %1 can not be less than from date %2", toDate, fromDate));
        }
        qbdsCustInvoiceJour.addRange(fieldNum(CustInvoiceJour, InvoiceDate)).value(queryRange(fromDate, toDate));
    }
    else
    {
        qbdsCustInvoiceJour.addRange(fieldNum(CustInvoiceJour, InvoiceDate)).value(
            strFmt("<=%1", date2Str(toDate, 123, DateMonth::Digits2, DateSeparator::Slash, DateDay::Digits2, DateSeparator::Slash, DateYear::Digits4)));
    }

    qbdsCustInvoiceJour.addRange(fieldNum(CustInvoiceJour, SalesId)).value(SysQuery::valueNotEmptyString());

    this.initializeMainAccount();

    queryRun = new QueryRun(query);

    while (queryRun.next())
    {
        custInvoiceJour = queryRun.get(tableNum(CustInvoiceJour));
        custInvoiceTrans = queryRun.get(tableNum(CustInvoiceTrans));

        select firstonly custTable
            where custTable.AccountNum == custInvoiceJour.InvoiceAccount;

        salesLine = custInvoiceTrans.salesLine();
        salesTable = custInvoiceJour.salesTable();

        select firstonly salesTableTrade
         where salesTableTrade.SalesId == salesTable.SalesId;

        salesAgreementHeader.clear();
        agreementHeader.clear();
        if (salesTable.MatchingAgreement)
        {
            select firstonly agreementHeader
                where agreementHeader.RecId == salesTable.MatchingAgreement;
        }
        if(agreementHeader.RecId)
        {
            select firstonly salesAgreementHeader
                 where agreementHeader.RecId == salesAgreementHeader.RecId;
        }



        etggmctableTemp.clear();

        etggmctableTemp.AccountNum     = custTable.AccountNum;
        etggmctableTemp.InvoiceAccount = custInvoiceJour.InvoiceId;
        etggmctableTemp.InvoiceDate    = custInvoiceTrans.InvoiceDate;

        etggmctableTemp.ETGMonth = strFmt('%1/%2',
            mthName(mthOfYr(custInvoiceTrans.InvoiceDate)),
            subStr(int2str(year(custInvoiceTrans.InvoiceDate)), 3, 2));

        etggmctableTemp.ORIGIN        = custInvoiceTrans.inventDim().InventColorId;
        etggmctableTemp.DESTINATION   = salesTableTrade.CountryOfFinalDestination;
        etggmctableTemp.SalesParty    = custTable.name();

        Amount purchCost;
        select firstonly RecId from inventTransOrigin
             where inventTransOrigin.InventTransId == custInvoiceTrans.InventTransId;

        if (inventTransOrigin.RecId)
        {

            while select inventTrans
            where inventTrans.InvoiceId == custInvoiceTrans.InvoiceId
             && inventTrans.ItemId == custInvoiceTrans.ItemId
            && inventTrans.InventTransOrigin == inventTransOrigin.RecId
            {
                purchCost += abs(inventTrans.costValue());
            }
        }

        etggmctableTemp.PurchaseCost = purchCost;

        etggmctableTemp.ContractNo = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(salesTable.DefaultDimension, acfParameters.Contract);
        etggmctableTemp.ItemId = custInvoiceTrans.ItemId;
        etggmctableTemp.ItemDesc = custInvoiceTrans.Name;


        //accountNum  = SalesAgreementHeader::findAgreementId(contract).CustAccount;
        etggmctableTemp.AgreementNum = salesAgreementHeader.SalesNumberSequence;




        etggmctableTemp.Vertical = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(
            salesLine.DefaultDimension, acfParameters.Vertical);

        etggmctableTemp.SubVertical = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(
            salesLine.DefaultDimension, acfParameters.SubVertical);

        etggmctableTemp.MainCommodity = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(
            salesLine.DefaultDimension, acfParameters.MainCommodity);

        etggmctableTemp.SubCommodity = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(
            salesLine.DefaultDimension, acfParameters.SubCommodity);

        etggmctableTemp.SalesQty     = custInvoiceTrans.Qty;
        etggmctableTemp.SalesUnit    = custInvoiceTrans.SalesUnit;
        etggmctableTemp.LineAmount   = custInvoiceTrans.LineAmountMST;

        if(etggmctableTemp.SalesQty < 0)
        {
            etggmctableTemp.PurchaseCost =  etggmctableTemp.PurchaseCost * (-1);
        }

        //QTY in MT code
        str                      fromUnit,toUnit;
        UnitOfMeasure            fromUnitOfMeasure, toUnitOfMeasure;
        InventTableModule        inventTableModule;
        InventTable              inventTableloc;
        UnitOfMeasureConversion  unitOfMeasureConversion;
        inventTableloc       = InventTable::find(custInvoiceTrans.ItemId);
        fromUnit             = custInvoiceTrans.SalesUnit;
        fromUnitOfMeasure    = UnitOfMeasure::findBySymbol(fromUnit);
        boolean           isvaild;

        while select unitOfMeasureConversion
            where unitOfMeasureConversion.FromUnitOfMeasure  == fromUnitOfMeasure.RecId
        {
            toUnit   = UnitOfMeasure::find(unitOfMeasureConversion.ToUnitOfMeasure).Symbol;

            if(unitOfMeasureConversion.FromUnitOfMeasure  == fromUnitOfMeasure.RecId && unitOfMeasureConversion.Product == 0)
            {
                if(fromUnit == toUnit && toUnit == "@ETG_New:MT")
                {
                    etggmctableTemp.ETGMT = etggmctableTemp.SalesQty;
                    isvaild = true;
                }
                else if(fromUnit  && toUnit == "@ETG_New:MT")
                {
                    etggmctableTemp.ETGMT = unitOfMeasureConversion.Factor * etggmctableTemp.SalesQty;
                    isvaild = true;
                }
            }
            else
            {
                if(!isvaild)
                {
                    select firstonly  unitOfMeasureConversion
                        where unitOfMeasureConversion.Product  == inventTableloc.Product
                        &&   unitOfMeasureConversion.FromUnitOfMeasure == fromUnitOfMeasure.RecId;
                    if(fromUnit == toUnit && toUnit == "@ETG_New:MT")
                    {
                        etggmctableTemp.ETGMT = etggmctableTemp.SalesQty;
                    }
                    else if(fromUnit  && toUnit == "@ETG_New:MT")
                    {
                        etggmctableTemp.ETGMT = unitOfMeasureConversion.Factor * etggmctableTemp.SalesQty;
                    }
                }
                if(etggmctableTemp.ETGMT == 0 && fromUnit =="MT")
                {
                    etggmctableTemp.ETGMT  = etggmctableTemp.SalesQty;
                }
            }
        }

        this.getMainAccountDetails(custInvoiceJour, custInvoiceTrans);

        //etggmctableTemp.insert();
        recordgmrReportTemp.add(etggmctableTemp);

    }
    recordgmrReportTemp.insertDatabase();

    this.insertNonInvoiceDataView();

    ttsbegin;

    this.groupByNonInvoiceData();

    ttscommit;

    //CustInvoiceJour    custInvoiceJourLoc;
    //container          conLedgerVoucher;
    //int                 counter = 1;

    //while select sum(SalesQty), ContractNo, Vertical, SubVertical, MainCommodity, SubCommodity   from gmrReportTemp
    //    group by gmrReportTemp.ContractNo,
    //             gmrReportTemp.Vertical,
