    recordgmrReportNonInvoiceTemp = new RecordInsertList(tableNum(ETGGMCTableTempNonInvoice));

    select firstonly gmrReportMainAccountName where gmrReportMainAccountName.DataAreaId == curExt();

    companyId = curExt();

    while select gmrReportView
            where gmrReportView.AccountingDate >= fromDate
                && gmrReportView.AccountingDate <= toDate
                && gmrReportView.SubledgerVoucherDataAreaId == companyId
          //notexists join custInvJour
          //  where custInvJour.LedgerVoucher == gmrReportView.SubledgerVoucher
    {

        select firstonly SalesId, RecId from custInvJour
            where custInvJour.LedgerVoucher == gmrReportView.SubledgerVoucher
            && custInvJour.DataAreaId == companyId;

